import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import './BlogList.css';

function BlogList({ blogs, loading, topics }) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedTopicId, setSelectedTopicId] = useState(null);

  const filteredBlogs = blogs.filter(blog => {
    const matchesSearch = blog.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         blog.content.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesTopic = selectedTopicId === null || blog.topicId === selectedTopicId;
    return matchesSearch && matchesTopic;
  });

  if (loading) {
    return <div className="loading">Loading blogs...</div>;
  }

  return (
    <div className="blog-list-container">
      <div className="filters">
        <input
          type="text"
          placeholder="Search blogs..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="search-input"
        />
        <div className="topic-filter">
          <button
            className={`topic-btn ${selectedTopicId === null ? 'active' : ''}`}
            onClick={() => setSelectedTopicId(null)}
          >
            All
          </button>
          {topics.map(topic => (
            <button
              key={topic.id}
              className={`topic-btn ${selectedTopicId === topic.id ? 'active' : ''}`}
              onClick={() => setSelectedTopicId(topic.id)}
            >
              {topic.name}
            </button>
          ))}
        </div>
      </div>

      {filteredBlogs.length === 0 ? (
        <div className="no-blogs">
          <p>No blog posts found. {searchTerm && 'Try a different search.'}</p>
          <Link to="/create" className="create-link">Create your first post</Link>
        </div>
      ) : (
        <div>
          {filteredBlogs.map(blog => (
            <article key={blog.id} className="blog-card">
              <div className="blog-header">
                <h2 className="blog-title">
                  {blog.title}
                </h2>
                <span className="blog-date">
                  {new Date(blog.created_at).toLocaleDateString()}
                </span>
              </div>
              <p className="blog-excerpt">
                {blog.content.substring(0, 1000)}...
              </p>
              <Link to={`/blog/${blog.id}`} className="read-more">
                ore →
              </Link>
            </article>
          ))}
        </div>
      )}
    </div>
  );
}

export default BlogList;
